function i(){const s=document.getElementById("desplegable"),t=document.getElementById("menu"),r=document.getElementById("correo");t.hidden=!0,s.addEventListener("click",e=>{e.preventDefault(),t.hidden=!t.hidden}),fetch("/api/auth/obtenerMensajes").then(e=>{if(!e.ok)throw new Error("No se han podido obtener los mensajes");return e.json()}).then(e=>{let n=!1;e.forEach(o=>{o.es_destinatario==!0&&o.leido===!1&&(n=!0)}),n===!0&&(r.style.animation="tienesCorreo 2s 1s")})}export{i};
